using System;
using System.Collections.Generic;
using System.Text.Json;
using System.Text.Json.Serialization;

namespace Azure.ResourceManager
{
    [JsonSerializable(typeof(Dictionary<string, string>))]
    [JsonSerializable(typeof(Dictionary<string, Dictionary<string, JsonElement>>))]
    [JsonSerializable(typeof(ArmEnvironment))]
    internal partial class ArmJsonContext : JsonSerializerContext
    {
    }

    internal class ResponseErrorConverter : JsonConverter<ResponseError>
    {
        public override ResponseError Read(ref Utf8JsonReader reader, Type typeToConvert, JsonSerializerOptions options)
        {
            string code = null;
            string message = null;

            if (reader.TokenType != JsonTokenType.StartObject)
                throw new JsonException();

            while (reader.Read())
            {
                if (reader.TokenType == JsonTokenType.EndObject)
                    break;

                if (reader.TokenType != JsonTokenType.PropertyName)
                    continue;

                string propName = reader.GetString();
                reader.Read();

                switch (propName)
                {
                    case "code":
                        code = reader.GetString();
                        break;
                    case "message":
                        message = reader.GetString();
                        break;
                    default:
                        reader.Skip();
                        break;
                }
            }

            return new ResponseError(code, message);
        }

        public override void Write(Utf8JsonWriter writer, ResponseError value, JsonSerializerOptions options)
        {
            writer.WriteStartObject();
            if (value.Code != null)
            {
                writer.WriteString("code", value.Code);
            }
            if (value.Message != null)
            {
                writer.WriteString("message", value.Message);
            }
            writer.WriteEndObject();
        }
    }
}

